@* Displays a single task card with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between mt-2">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="() => OnMoveLeft.InvokeAsync(Task)">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="() => OnMoveRight.InvokeAsync(Task)">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for adding a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-sm btn-primary" @onclick="Save">Save</button>
            <button class="btn btn-sm btn-secondary" @onclick="Cancel">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<NewTaskModel> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;
        await OnSave.InvokeAsync(new NewTaskModel(Title, Assignee, Priority, DueDate, Status));
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();

    public record NewTaskModel(string Title, string Assignee, string Priority, DateTime DueDate, string Status);
}

@* A single Kanban column with header, task cards, and add form *@

<div class="col-md-4">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 60vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }

            @if (showForm)
            {
                <AddTaskForm Status="@ColumnName"
                             OnSave="HandleSave"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => showForm = true">+ Add Task</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<AddTaskForm.NewTaskModel> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleSave(AddTaskForm.NewTaskModel model)
    {
        await OnTaskCreated.InvokeAsync(model);
        showForm = false;
    }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTextChanged.InvokeAsync(value);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Total="allTasks.Count"
                ToDo="GetTasksForStatus("To Do").Count"
                InProgress="GetTasksForStatus("In Progress").Count"
                Done="GetTasksForStatus("Done").Count"
                Overdue="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <TaskSearchBar SearchText="@searchText" SearchTextChanged="text => { searchText = text; }" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasksForStatus("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="task => MoveTask(task, "In Progress")"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasksForStatus("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="task => MoveTask(task, "To Do")"
                      OnMoveRight="task => MoveTask(task, "Done")"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasksForStatus("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="task => MoveTask(task, "In Progress")"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetTasksForStatus(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForStatus(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(searchText) || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(AddTaskForm.NewTaskModel model)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

