@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetTasksForStatus(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForStatus(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(searchText) || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(AddTaskForm.NewTaskModel model)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

